final:
module top_module(
		input	clk, 
		input	rst, 
		input	count, 
		output [3:0]	counter_value
	);reg [3:0] invalid_counter;


assign counter_value = invalid_counter;

always@(posedge clk or posedge rst) begin
	if(rst == 1'b1) begin
		invalid_counter = 4'h0;
	end else if ( count == 1'b1 ) begin
		invalid_counter = invalid_counter + 1;
	end else begin
		invalid_counter = counter_value;
	end
end

endmodule
